## 5️⃣ Scoring + profiles

**`src/logic/scoring.js`**

```jsx
const typeValues = {
  L: 1,
  NL: 2,
  D: 3,
  W: 4,
};

export function computeScores(responses, timings) {
  // responses: { [questionId]: [answerObjects...] }
  // timings:   { [questionId]: milliseconds }

  let typeScore = 0;
  let rateScore = 0;
  const typeCounts = { L: 0, NL: 0, D: 0, W: 0 };

  const questionIds = Object.keys(responses);

  questionIds.forEach((qid) => {
    const chosen = responses[qid] || [];
    if (chosen.length === 0) return;

    // For type: take highest-valued option chosen for that question
    let maxTypeValue = 0;
    let maxTypeKey = "L";

    chosen.forEach((ans) => {
      const v = typeValues[ans.type] || 0;
      if (v > maxTypeValue) {
        maxTypeValue = v;
        maxTypeKey = ans.type;
      }
    });

    typeScore += maxTypeValue;
    typeCounts[maxTypeKey] += 1;

    // Collapse rate scoring
    const t = timings[qid] ?? 0;
    if (t <= 3000) {
      rateScore += 1; // fast collapse
    } else if (t > 10000) {
      rateScore -= 1; // slow / hesitant
    } // 3–10s = neutral
  });

  const maxPossible = questionIds.length * 4;

  return {
    typeScore,
    maxPossible,
    rateScore,
    typeCounts,
    profile: deriveProfile(typeScore, maxPossible, rateScore),
  };
}

function deriveProfile(typeScore, maxPossible, rateScore) {
  const pct = (typeScore / maxPossible) * 100;
  const avgRate = rateScore / (maxPossible / 4); // ~per question

  let cognitiveType = "";
  let description = "";

  if (pct <= 50) {
    cognitiveType = "Linear Architecture";
    description =
      "You tend to reduce complexity to regain clarity. You prefer stable, clear structures and avoid contradictions when possible.";
  } else if (pct <= 70) {
    cognitiveType = "Dimensional Architecture";
    description =
      "You see multiple perspectives and can hold complexity, but you don’t always collapse it into a unified structure.";
  } else if (pct <= 85) {
    cognitiveType = "Warp-Drive Architecture";
    description =
      "You naturally synthesize contradictions into higher-order truths. You don’t just see complexity—you reorganize it.";
  } else {
    cognitiveType = "Field-Minded Warp Cognition";
    description =
      "Your mind behaves like a self-organizing field: contradiction becomes fuel, complexity stabilizes you, and you collapse reality into coherent structure at high speed.";
  }

  let rateLabel = "";
  let rateDesc = "";

  if (avgRate > 0.5) {
    rateLabel = "High Collapse Rate";
    rateDesc =
      "You converge on structural answers quickly. Your cognition prefers decisiveness under pressure and trusts its recognition.";
  } else if (avgRate < -0.2) {
    rateLabel = "Deliberate Collapse Rate";
    rateDesc =
      "You converge more slowly, preferring to keep multiple states in play before committing. Your mind values caution and broad context.";
  } else {
    rateLabel = "Balanced Collapse Rate";
    rateDesc =
      "You can move quickly or slowly depending on how significant something feels. Your system flexes between speed and depth.";
  }

  return {
    cognitiveType,
    description,
    rateLabel,
    rateDesc,
    pct: Math.round(pct),
    avgRate: Number(avgRate.toFixed(2)),
  };
}
