import React from "react";

export default function QuestionCard({
  question,
  selectedAnswers,
  onSelect,
  index,
  total,
  timeSeconds,
}) {
  const handleChange = (answer) => {
    if (question.allowMultiple) {
      const exists = selectedAnswers.find((a) => a.id === answer.id);
      if (exists) {
        onSelect(selectedAnswers.filter((a) => a.id !== answer.id));
      } else {
        onSelect([...selectedAnswers, answer]);
      }
    } else {
      onSelect([answer]);
    }
  };

  const isSelected = (id) =>
    !!selectedAnswers.find((a) => a.id === id);

  return (
    <div className="card">
      <div className="card-header">
        <div>Question {index + 1} of {total}</div>
        <div className="timer">Time: {timeSeconds}s</div>
      </div>
      <h2 className="question-text">{question.text}</h2>
      <div className="answers">
        {question.answers.map((ans) => (
          <label key={ans.id} className="answer-option">
            <input
              type={question.allowMultiple ? "checkbox" : "radio"}
              name={`q-${question.id}`}
              checked={isSelected(ans.id)}
              onChange={() => handleChange(ans)}
            />
            <span>{ans.text}</span>
          </label>
        ))}
      </div>
      {question.allowMultiple && (
        <p className="hint">
          You may select more than one if more than one feels true.
        </p>
      )}
    </div>
  );
}
