## 8️⃣ Main App logic

**`src/App.jsx`**

```jsx
import React, { useState, useEffect } from "react";
import { questions } from "./data/questions.js";
import QuestionCard from "./components/QuestionCard.jsx";
import ResultView from "./components/ResultView.jsx";
import { computeScores } from "./logic/scoring.js";

function shuffleArray(arr) {
  return [...arr].sort(() => Math.random() - 0.5);
}

export default function App() {
  // Shuffle answers per question on load to avoid pattern gaming
  const [shuffledQuestions] = useState(() =>
    questions.map((q) => ({
      ...q,
      answers: shuffleArray(q.answers),
    }))
  );

  const [currentIndex, setCurrentIndex] = useState(0);
  const [responses, setResponses] = useState({});
  const [timings, setTimings] = useState({});
  const [questionStart, setQuestionStart] = useState(Date.now());
  const [elapsed, setElapsed] = useState(0);
  const [finished, setFinished] = useState(false);
  const [profile, setProfile] = useState(null);

  const currentQuestion = shuffledQuestions[currentIndex];

  // Timer side-effect
  useEffect(() => {
    const interval = setInterval(() => {
      setElapsed(Math.floor((Date.now() - questionStart) / 1000));
    }, 200);
    return () => clearInterval(interval);
  }, [questionStart]);

  const handleSelect = (answers) => {
    setResponses((prev) => ({
      ...prev,
      [currentQuestion.id]: answers,
    }));
  };

  const goNext = () => {
    // store timing for this question
    const now = Date.now();
    const ms = now - questionStart;
    setTimings((prev) => ({
      ...prev,
      [currentQuestion.id]: ms,
    }));

    if (currentIndex === shuffledQuestions.length - 1) {
      // finish
      const scores = computeScores(
        { ...responses, [currentQuestion.id]: responses[currentQuestion.id] || [] },
        { ...timings, [currentQuestion.id]: ms }
      );
      setProfile(scores.profile);
      setFinished(true);
    } else {
      setCurrentIndex((i) => i + 1);
      setQuestionStart(Date.now());
      setElapsed(0);
    }
  };

  const canContinue =
    responses[currentQuestion?.id] &&
    responses[currentQuestion.id].length > 0;

  const handleRestart = () => {
    window.location.reload();
  };

  return (
    <div className="app-container">
      <h1 className="title">Warp-Drive Cognitive Diagnostic</h1>

      {!finished && currentQuestion && (
        <>
          <QuestionCard
            question={currentQuestion}
            selectedAnswers={responses[currentQuestion.id] || []}
            onSelect={handleSelect}
            index={currentIndex}
            total={shuffledQuestions.length}
            timeSeconds={elapsed}
          />
          <button
            className="btn primary"
            onClick={goNext}
            disabled={!canContinue}
          >
            {currentIndex === shuffledQuestions.length - 1
              ? "Finish Test"
              : "Next Question"}
          </button>
        </>
      )}

      {finished && profile && (
        <ResultView profile={profile} onRestart={handleRestart} />
      )}

      {!finished && (
        <p className="footer-note">
          Choose the answer(s) that feel structurally inevitable, not just
          comfortable.
        </p>
      )}
    </div>
  );
}
```

